import React, { useEffect, useState } from 'react';

const ProjectHub = () => {
  const [projects, setProjects] = useState([]);

  useEffect(() => {
    // Replace with actual API call later
    setProjects([
      { name: "Turbinix MVP", status: "In Progress" },
      { name: "Finance Dashboard", status: "Coming Soon" }
    ]);
  }, []);

  return (
    <div className="p-6">
      <h1 className="text-3xl font-bold mb-4">Project Hub</h1>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {projects.map((proj, index) => (
          <div key={index} className="border rounded-xl p-4 shadow bg-white">
            <h2 className="text-xl font-semibold">{proj.name}</h2>
            <p className="text-gray-600">Status: {proj.status}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ProjectHub;
